// Extract summary data and store per video
const summaryData = $('6. WayinVideo — Get Summary Results').item.json.data;
const videoUrl = $('2. Google Sheets — Read Pending Videos').item.json['Video URL'];
const videoTitle = $('2. Google Sheets — Read Pending Videos').item.json['Video Title'] || 'Untitled';
const niche = $('2. Google Sheets — Read Pending Videos').item.json['Niche / Category'] || 'General';
const dateAdded = $('2. Google Sheets — Read Pending Videos').item.json['Date Added'] || new Date().toISOString().split('T')[0];

// Extract summary fields
const summary = summaryData.summary || '';
const highlights = Array.isArray(summaryData.highlights)
  ? summaryData.highlights.map(h => h.desc).filter(Boolean)
  : [];
const tags = Array.isArray(summaryData.tags)
  ? summaryData.tags
  : [];

return [{
  json: {
    videoUrl,
    videoTitle,
    niche,
    dateAdded,
    summary,
    highlights,
    tags,
    highlightsText: highlights.join(' | '),
    tagsText: tags.join(', ')
  }
}];

// Aggregate all video summaries into one item for the AI digest
// This node collects all items processed so far
const allItems = $input.all();

if (allItems.length === 0) {
  throw new Error('No video summaries to compile into digest.');
}

// Build combined text for GPT
const allVideoSummaries = allItems.map((item, index) => {
  const data = item.json;
  return [
    `VIDEO ${index + 1}: ${data.videoTitle}`,
    `URL: ${data.videoUrl}`,
    `Summary: ${data.summary}`,
    `Key Highlights: ${data.highlightsText}`,
    `Tags: ${data.tagsText}`,
    `---`
  ].join('\n');
}).join('\n');

const niche = allItems[0].json.niche || 'General';
const videoUrls = allItems.map(item => item.json.videoUrl);

return [{
  json: {
    allVideoSummaries,
    totalVideos: allItems.length,
    niche,
    videoUrls
  }
}];

// Parse AI digest output and format for Telegram
const output = $input.first().json.output || '';
const niche = $input.first().json.niche || 'General';
const totalVideos = $input.first().json.totalVideos || 0;
const videoUrls = $input.first().json.videoUrls || [];

// Extract sections
const overviewMatch = output.match(/DIGEST_OVERVIEW:\s*([\s\S]*?)(?=\nVIDEO_SUMMARIES:|$)/);
const summariesMatch = output.match(/VIDEO_SUMMARIES:\s*([\s\S]*?)(?=\nTOP_PATTERNS:|$)/);
const patternsMatch = output.match(/TOP_PATTERNS:\s*([\s\S]*?)(?=\nACTION_RECOMMENDATIONS:|$)/);
const actionsMatch = output.match(/ACTION_RECOMMENDATIONS:\s*([\s\S]*?)(?=\nTOP_TAGS:|$)/);
const tagsMatch = output.match(/TOP_TAGS:\s*([\s\S]*)$/);

const overview = overviewMatch ? overviewMatch[1].trim() : '';
const videoSummaries = summariesMatch ? summariesMatch[1].trim() : '';
const topPatterns = patternsMatch ? patternsMatch[1].trim() : '';
const actionRecs = actionsMatch ? actionsMatch[1].trim() : '';
const topTags = tagsMatch ? tagsMatch[1].trim() : '';

// Build Telegram message
const today = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

const telegramMessage = [
  `📱 *TikTok Trend Digest — ${today}*`,
  `_Niche: ${niche} | Videos Tracked: ${totalVideos}_`,
  ``,
  `📊 *Overview*`,
  overview,
  ``,
  `🎬 *Today's Videos*`,
  videoSummaries,
  ``,
  `🔥 *Top Content Patterns*`,
  topPatterns,
  ``,
  `✅ *Action Recommendations*`,
  actionRecs,
  ``,
  `🏷️ *Trending Tags*`,
  topTags,
  ``,
  `_Powered by WayinVideo + GPT-4o-mini_`
].join('\n');

// Truncate if over Telegram limit
const truncated = telegramMessage.length > 4000
  ? telegramMessage.substring(0, 3900) + '...\n\n_Message truncated — check digest log for full version_'
  : telegramMessage;

return [{
  json: {
    telegramMessage: truncated,
    overview,
    videoSummaries,
    topPatterns,
    actionRecs,
    topTags,
    niche,
    totalVideos,
    digestDate: today
  }
}];
